// =============================
// C1: System Under Study
// =============================
instance AutonomousScaleVehicle : DTDFVocab:Component [
    base:desc "1/10‑scale autonomous vehicle retrofitted from a Traxxas Slash 4x4 platform, equipped with lower chassis (steering/speed control), upper chassis hosting NVIDIA Jetson NX antenna, Jetson Orin Nano, Hokuyo UST‑10LX LiDAR, Intel RealSense D435i depth camera, and Vedder ESC."
]

// =============================
// C2: Acting Components
// =============================
// Motor drive actuator
instance VedderElectronicSpeedController : DTDFVocab:ActingComponent [
    base:desc "Vedder ESC that actuates vehicle speed by modulating motor voltage."
]

// Steering actuator
instance SteeringServo : DTDFVocab:ActingComponent [
    base:desc "Servo motor that actuates the steering angle of the 1/10‑scale vehicle."
]

// Emergency brake actuator (via motor voltage = 0)
instance EmergencyBrakeActuator : DTDFVocab:ActingComponent [
    base:desc "Acts as an emergency brake by setting motor voltage to zero through the Vedder ESC."
]

// =============================
// C3: Physical Sensing Components
// =============================
// LiDAR sensor
instance HokuyoUST10LXLidar : DTDFVocab:SensingComponent [
    base:desc "Hokuyo UST‑10LX 2‑D LiDAR providing real‑time point‑cloud data.",
    producedData LiDARPointCloudDataTransmitted
]

// Depth camera sensor
instance IntelRealSenseD435iCamera : DTDFVocab:SensingComponent [
    base:desc "Intel RealSense D435i depth camera delivering RGB‑D frames.",
    producedData CameraDepthDataTransmitted
]

// Vehicle speed sensor (ego speed)
instance VehicleSpeedSensor : DTDFVocab:SensingComponent [
    base:desc "On‑board wheel‑speed sensor delivering the ego‑vehicle speed.",
    producedData SpeedDataTransmitted
]

// Steering‑angle sensor
instance SteeringAngleSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor measuring the current steering angle of the vehicle.",
    producedData SteeringAngleDataTransmitted
]

// =============================
// C4: Data Transmitted (ROS2 Topics)
// =============================
// LiDAR point‑cloud topic
instance LiDARPointCloudDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom HokuyoUST10LXLidar
]

// Depth‑image topic
instance CameraDepthDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom IntelRealSenseD435iCamera
]

// Speed topic
instance SpeedDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom VehicleSpeedSensor
]

// Steering angle topic
instance SteeringAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SteeringAngleSensor
]

// =============================
// C17: Insights & Actions
// =============================
// Insight – Vehicle state report
instance VehicleStateReportInsight : DTDFVocab:Insight [
    base:desc "Human‑readable time‑series report of vehicle speed, steering angle, and detected object tracks."
]

// Insight – Projected path visualization
instance ProjectedPathVisualizationInsight : DTDFVocab:Insight [
    base:desc "Visualization of current vehicle trajectory and predicted paths of surrounding objects."
]

// Insight – ACC command output
instance ACCCommandInsight : DTDFVocab:Insight [
    base:desc "Computed ACC speed set‑point presented to the operator for verification."
]

// Action – Adjust ACC settings
instance AdjustACCSettingsAction : DTDFVocab:Action [
    base:desc "Operator changes ACC target speed or following distance via the UI.",
    DTDFVocab:IsAutomatic false
]

// Action – Emergency brake
instance EmergencyBrakeAction : DTDFVocab:Action [
    base:desc "Operator triggers emergency stop Digital Twin commands motor voltage = 0 via EmergencyBrakeActuator.",
    DTDFVocab:IsAutomatic false
]

// =============================
// C6: Services
// =============================
// Service 1 – Data Monitoring
instance DataMonitoringService : DTDFVocab:Service [
    base:desc "UI visualizes real‑time vehicle state, projected paths, and object tracks, stores data and generates reports.",
    provides VehicleStateReportInsight, ProjectedPathVisualizationInsight
]

// Service 2 – Computation Offloading
