]

// Service 3 – Remote Management
instance RemoteManagementService : DTDFVocab:Service [
    base:desc "Allows remote enable/disable of ACC, speed set‑point changes, and emergency braking.",
    provides EmergencyBrakeAction, AdjustACCSettingsAction
]

